<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">   CREATE INDEX idx_gender ON </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">users</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(gender);</span></span>
